import React, { useEffect, useState } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";

function App() {

  const [jobs, setJobs] = useState([]);

  const [applications, setApplications] = useState([]);

  const [email, setEmail] = useState("");

  const [password, setPassword] = useState("");

  const [isLoggedIn, setIsLoggedIn] = useState(false);

  const [showApplications, setShowApplications] = useState(false);

  useEffect(() => {

    axios.get("https://localhost:7059/api/Jobs")
      .then(response => {
        setJobs(response.data);
      })
      .catch(error => {
        console.error(error);
      });

  }, []);

  const login = async () => {

    try {

      const response = await axios.post(
        "https://localhost:7059/api/Auth/login",
        {
          email,
          password
        }
      );

      localStorage.setItem("token", response.data.token);

      setIsLoggedIn(true);

    } catch {

      alert("Login failed");

    }
  };

  const applyToJob = async (jobId) => {

    try {

      const token = localStorage.getItem("token");

      await axios.post(
        "https://localhost:7059/api/Applications",
        {
          jobId: jobId
        },
        {
          headers: {
            Authorization: `Bearer ${token}`
          }
        }
      );

      alert("Application sent!");

    } catch (error) {

      console.error(error);

      alert("Could not apply");

    }
  };

  const loadApplications = async () => {

    try {

      const response = await axios.get(
        "https://localhost:7059/api/Applications"
      );

      setApplications(response.data);

      setShowApplications(true);

    } catch (error) {

      console.error(error);

      alert("Could not load applications");

    }
  };

  if (!isLoggedIn) {

    return (

      <div className="container mt-5">

        <div className="row justify-content-center">

          <div className="col-md-4">

            <div className="card shadow p-4">

              <h2 className="text-center mb-4">
                Login
              </h2>

              <input
                type="email"
                placeholder="Email"
                className="form-control mb-3"
                onChange={(e) => setEmail(e.target.value)}
              />

              <input
                type="password"
                placeholder="Password"
                className="form-control mb-3"
                onChange={(e) => setPassword(e.target.value)}
              />

              <button
                className="btn btn-primary"
                onClick={login}
              >
                Login
              </button>

            </div>

          </div>

        </div>

      </div>
    );
  }

  return (

    <div className="container mt-5">

      <div className="d-flex justify-content-between mb-4">

        <h1>
          Recruitment Platform
        </h1>

        <button
          className="btn btn-dark"
          onClick={loadApplications}
        >
          View Applications
        </button>

      </div>

      {showApplications && (

        <div className="mb-5">

          <h2 className="mb-3">
            Applications
          </h2>

          <table className="table table-bordered">

            <thead>

              <tr>

                <th>ID</th>

                <th>Job</th>

                <th>Candidate</th>

              </tr>

            </thead>

            <tbody>

              {applications.map(app => (

                <tr key={app.id}>

                  <td>{app.id}</td>

                  <td>{app.job?.title}</td>

                  <td>{app.candidateId}</td>

                </tr>

              ))}

            </tbody>

          </table>

        </div>

      )}

      <div className="row">

        {jobs.map(job => (

          <div className="col-md-4 mb-4" key={job.id}>

            <div className="card shadow">

              <div className="card-body">

                <h5 className="card-title">
                  {job.title}
                </h5>

                <p className="card-text">
                  {job.description}
                </p>

                <p>
                  <strong>Location:</strong> {job.location}
                </p>

                <p>
                  <strong>Salary:</strong> {job.salary} SEK
                </p>

                <button
                  className="btn btn-success w-100"
                  onClick={() => applyToJob(job.id)}
                >
                  Apply
                </button>

              </div>

            </div>

          </div>

        ))}

      </div>

    </div>
  );
}

export default App;
